  let response;
  try {
    response = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}?oppNum=eq.${encodeURIComponent(oppNum)}&select=id,source_id,title`
,
      headers: {
        'apikey': supabaseKey,
        'Authorization': 'Bearer ' + supabaseKey,
      },
    });
  } catch (e) {
    // If fetch fails, include it so it can be retried manually
    results.push({
      json: {
        grant,
        status: 'error',
        message: e.message,
      },
    });
    continue;
  }

  if (!Array.isArray(response)) {
    // If Supabase returns something unexpected, skip it
    results.push({
      json: {
        grant,
        status: 'invalid response',
        message: 'Unexpected Supabase response',
        rawResponse: response,
      },
    });
    continue;
  }

  if (response.length === 0) {
